public int longestBeautifulSubstring(String word) {
    if (word.length() < 5) return 0;

    int maxLength = 0, currentLength = 1;
    StringBuilder currentVowels = new StringBuilder(String.valueOf(word.charAt(0)));

    for (int i = 1; i < word.length(); ++i) {
        char currentChar = word.charAt(i);
        if (currentChar >= currentVowels.charAt(currentVowels.length() - 1) && currentVowels.indexOf(String.valueOf(currentChar)) == -1) {
            currentVowels.append(currentChar);
        } else if (currentChar == currentVowels.charAt(currentVowels.length() - 1)) {
            // Do nothing
        } else {
            currentVowels = new StringBuilder(String.valueOf(currentChar));
            currentLength = 0;
        }

        currentLength++;

        if (currentVowels.toString().equals("aeiou")) {
            maxLength = Math.max(maxLength, currentLength);
        }
    }

    return maxLength;
}
